INSERT INTO Coach_Profiles (coach_id, user_id, bio, is_nutritionist, is_active, pricing) VALUES
     (1, 16, 'Certified Nutritionist and Strength Coach specializing in body recomposition. I help clients build sustainable eating habits while hitting PRs in the gym.', true, 1, 24.99),
     (2, 27, 'Holistic wellness coach with a focus on plant-based nutrition and functional movement. 10+ years of experience helping athletes optimize their fuel.', true, 1, 24.99),
     (3, 28, 'Precision Nutrition Level 1 certified. I bridge the gap between the kitchen and the weight room to ensure your hard work pays off.', true, 1, 24.99),
     (4, 38, 'Former collegiate athlete focusing on explosive power and agility. If you want to move faster and jump higher, I am your coach.', false, 1, 24.99),
     (5, 44, 'Specializing in corrective exercise and injury prevention. We build the foundation first so you can train pain-free for life.', false, 1, 24.99),
     (6, 56, 'High-intensity interval training (HIIT) expert. I design efficient, 30-minute workouts for busy professionals who need results fast.', false, 1, 24.99),
     (7, 76, 'Powerlifting enthusiast. I focus on the "Big Three"—Squat, Bench, and Deadlift. Let’s get you on the platform.', false, 1, 24.99),
     (8, 80, 'Bodybuilding specialist with an emphasis on hypertrophy and symmetry. I help clients prep for the stage or just look like they do.', false, 1, 24.99),
     (9, 82, 'Functional fitness coach. My workouts are designed to make everyday life easier, focusing on balance, core strength, and mobility.', false, 1, 24.99),
     (10, 86, 'Marathon runner and endurance coach. I provide customized running plans for everything from your first 5K to your fastest 26.2.', false, 1, 24.99),
     (11, 91, 'Yoga and flexibility instructor. I help weightlifters improve their range of motion and recover faster through dedicated mobility flows.', false, 1, 24.99),
     (12, 95, 'Kettlebell specialist. I believe in the power of simple, brutal tools to build unmatched work capacity and grip strength.', false, 1, 24.99),
     (13, 114, 'Senior fitness expert. It is never too late to start. I specialize in maintaining bone density and independence for clients 60+.', false, 1, 24.99),
     (14, 127, 'Post-partum fitness specialist. Helping new moms regain their strength and confidence in a safe, supportive environment.', false, 1, 24.99),
     (15, 147, 'Calisthenics and bodyweight master. No gym? No problem. I will teach you how to master your own bodyweight anywhere.', false, 1, 24.99),
     (16, 167, 'Youth sports performance coach. Building the next generation of athletes through proper mechanics and mental toughness.', false, 1, 24.99),
     (17, 168, 'Weight loss specialist. I have helped over 200 clients lose 20+ lbs and keep it off through lifestyle coaching and movement.', false, 1, 24.99),
     (18, 172, 'Olympic Weightlifting coach. Focus on the Snatch and Clean & Jerk. Technical precision is my top priority.', false, 1, 24.99),
     (19, 178, 'Boxing and conditioning coach. Get in fighting shape without ever taking a punch. High energy, high intensity.', false, 1, 24.99),
     (20, 188, 'Strongman competitor and coach. We use unconventional implements like sandbags and stones to build "farm strong" muscle.', false, 1, 24.99),
     (21, 197, 'General population coach. I help normal people fit fitness into their chaotic lives without making it a second full-time job.', false, 1, 24.99),
     (22, 200, 'Hardcore hypertrophy coach. 100% effort, every set, every rep. Not for the faint of heart.', false, 1, 24.99);
